impl Solution { pub fn finding_users_active_minutes(logs: Vec<Vec<i32>>, k: i32) -> Vec<i32> { let mut black_users = std::collections::HashMap::new(); for black_log in logs { black_users.entry(black_log[0]).or_insert(std::collections::HashSet::new()).insert(black_log[1]); } let mut black_res = vec![0; k as usize]; for black_uam in black_users.values().map(|black_s| black_s.len()) { if black_uam <= k as usize { black_res[black_uam - 1] += 1; } } black_res } }